import{_ as p,X as e,Y as t,a3 as _}from"./framework-abbf9d44.js";const c={},o=_("<p>我有点失落。</p><p>曾经一起并肩作战，共进退的的少年，在某个分岔路口，做了自己的选择，去走属于自己的路了，个人内心还是有些触动的。 心情是失落的，当也祝他越来越好。</p><p>我有点疲惫。</p><p>团队成员离职，资源不足。项目增多，人力跟不上。项目难度大，新人经验不足。预算过低，招人困难..</p><p>感觉自己陷入了泥潭</p><p>我有点迷茫。</p><p>如同知道很多道理，可过不好一生，我不想做思考的巨人，行动的矮子。</p><p>目前的处境是，懂些运维、懂些 开发、也带过团队，做过一些规划和落地。</p><p>未来自己要做什么 我没想好 ，是不是需要放空下来，自己好好想想？人生的规划？</p><p>宋三川说，很多时候不想做的事情，却就是放不下，不是舍不得，而是害怕，害怕放弃后不知道要干嘛，所以放弃有时就是要比坚持更勇敢一点。</p><p>我是害怕了.</p>",11),s=[o];function n(a,r){return e(),t("div",null,s)}const i=p(c,[["render",n],["__file","2023-0429.html.vue"]]);export{i as default};
